import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import Plans from './pages/Plans';
import Trainers from './pages/Trainers';
import Progress from './pages/Progress';

export default function App() {
  return (
    <BrowserRouter>
      <Navbar />
      <Routes>
        <Route path='/' element={<Home />} />
        <Route path='/plans' element={<Plans />} />
        <Route path='/trainers' element={<Trainers />} />
        <Route path='/progress' element={<Progress />} />
      </Routes>
    </BrowserRouter>
  );
}

import React from 'react';
import { NavLink } from 'react-router-dom';

export default function Navbar() {
  const style = ({ isActive }) => ({ textDecoration: 'none', color: isActive ? '#0f172a' : '#64748b', fontWeight: isActive ? 700 : 500 });

  return (
    <nav style={{ borderBottom: '1px solid #e2e8f0', background: '#fff' }}>
      <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '16px 24px', display: 'flex', justifyContent: 'space-between' }}>
        <h2 style={{ margin: 0 }}>FitLife</h2>
        <div style={{ display: 'flex', gap: '18px' }}>
          <NavLink to='/' style={style}>Home</NavLink>
          <NavLink to='/plans' style={style}>Plans</NavLink>
          <NavLink to='/trainers' style={style}>Trainers</NavLink>
          <NavLink to='/progress' style={style}>Progress</NavLink>
        </div>
      </div>
    </nav>
  );
}

import React from 'react';

export default function PlanCard({ plan }) {
  return (
    <div style={{ border: '1px solid #e2e8f0', borderRadius: '14px', padding: '18px', background: '#fff' }}>
      <h3 style={{ marginTop: 0 }}>{plan.plan_name}</h3>
      <p style={{ color: '#64748b' }}>Duration: {plan.duration}</p>
      <p style={{ fontWeight: 700 }}>${plan.price}</p>
      <button style={{ marginTop: '8px', padding: '10px 14px', border: 'none', borderRadius: '10px', background: '#0f172a', color: '#fff' }}>Choose Plan</button>
    </div>
  );
}

import React from 'react';

export default function TrainerCard({ trainer }) {
  return (
    <div style={{ border: '1px solid #e2e8f0', borderRadius: '14px', padding: '18px', background: '#fff' }}>
      <h3 style={{ marginTop: 0 }}>{trainer.name}</h3>
      <p style={{ color: '#64748b' }}>{trainer.specialization}</p>
      <p>Experience: {trainer.experience}</p>
    </div>
  );
}

import React from 'react';

export default function Home() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <div style={{ background: '#f8fafc', borderRadius: '18px', padding: '32px', border: '1px solid #e2e8f0' }}>
        <h1>Train smarter, stay consistent</h1>
        <p style={{ color: '#64748b', maxWidth: '700px' }}>
          Explore membership plans, meet expert trainers, and keep track of your progress in one modern fitness dashboard.
        </p>
      </div>
    </div>
  );
}

import React from 'react';
import PlanCard from '../components/PlanCard';

const plans = [
  { id: 1, plan_name: 'Basic', duration: '1 Month', price: 25 },
  { id: 2, plan_name: 'Standard', duration: '3 Months', price: 65 },
  { id: 3, plan_name: 'Premium', duration: '6 Months', price: 120 }
];

export default function Plans() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Membership Plans</h1>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: '18px' }}>
        {plans.map(plan => <PlanCard key={plan.id} plan={plan} />)}
      </div>
    </div>
  );
}

import React from 'react';
import TrainerCard from '../components/TrainerCard';

const trainers = [
  { id: 1, name: 'Ahmed Khan', specialization: 'Strength Training', experience: '5 years' },
  { id: 2, name: 'Sara Malik', specialization: 'Yoga & Mobility', experience: '4 years' },
  { id: 3, name: 'Usman Ali', specialization: 'Weight Loss', experience: '6 years' }
];

export default function Trainers() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Trainers</h1>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: '18px' }}>
        {trainers.map(trainer => <TrainerCard key={trainer.id} trainer={trainer} />)}
      </div>
    </div>
  );
}

import React from 'react';

const progress = [
  { id: 1, metric: 'Workouts Completed', value: '18' },
  { id: 2, metric: 'Calories Burned', value: '4200 kcal' },
  { id: 3, metric: 'Weight Change', value: '-2.5 kg' }
];

export default function Progress() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Progress</h1>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: '18px' }}>
        {progress.map(item => (
          <div key={item.id} style={{ border: '1px solid #e2e8f0', borderRadius: '14px', padding: '18px', background: '#fff' }}>
            <p style={{ margin: '0 0 8px 0', color: '#64748b' }}>{item.metric}</p>
            <h3 style={{ margin: 0 }}>{item.value}</h3>
          </div>
        ))}
      </div>
    </div>
  );
}

from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/api/plans')
def get_plans():
    return jsonify({
        'plans': [
            {'id': 1, 'plan_name': 'Basic', 'duration': '1 Month', 'price': 25},
            {'id': 2, 'plan_name': 'Standard', 'duration': '3 Months', 'price': 65},
            {'id': 3, 'plan_name': 'Premium', 'duration': '6 Months', 'price': 120}
        ]
    })

@app.route('/api/trainers')
def get_trainers():
    return jsonify({
        'trainers': [
            {'id': 1, 'name': 'Ahmed Khan', 'specialization': 'Strength Training', 'experience': '5 years'},
            {'id': 2, 'name': 'Sara Malik', 'specialization': 'Yoga & Mobility', 'experience': '4 years'},
            {'id': 3, 'name': 'Usman Ali', 'specialization': 'Weight Loss', 'experience': '6 years'}
        ]
    })

if __name__ == '__main__':
    app.run(debug=True)
